const FOOTER_COPYRIGHT =
  '© 2025 Krungthai Bank PCL | SWIFT CODE: krththbk' as const

export function Footer() {
  return (
    <footer className="site-footer">
      <div className="site-footer__inner container mx-auto px-4">
        <div className="site-footer__grid">
          <div className="site-footer__columns">
            {FOOTER_COLUMNS.map((column) => (
              <div key={column.title} className="site-footer__column">
                <p className="site-footer__column-title type-label-small-medium">
                  {column.title}
                </p>
                <ul className="site-footer__link-list">
                  {column.links.map((link) => (
                    <li key={link.label} className="site-footer__link-item">
                      <Link
                        href={link.href}
                        className="site-footer__link type-body-base-regular"
                      >
                        {link.label}
                      </Link>
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>

          <div className="site-footer__social">
            <p className="site-footer__social-label type-label-small-medium">
              FIND US ON
            </p>
            <ul className="site-footer__social-row">
              {FOOTER_SOCIAL.map((item) => (
                <li key={item.label}>
                  <Link
                    href={item.href}
                    className={item.className}
                    aria-label={item.label}
                  >
                    {item.icon}
                  </Link>
                </li>
              ))}
            </ul>
          </div>
        </div>

        <div className="site-footer__bottom">
          <p className="site-footer__copyright type-body-base-regular">
            {FOOTER_COPYRIGHT}
          </p>
          <nav className="site-footer__legal" aria-label="Legal and policies">
            <ul className="site-footer__legal-list">
              {FOOTER_LEGAL.map((label, i) => (
                <Fragment key={label}>
                  {i > 0 ? (
                    <li className="site-footer__legal-sep-item" aria-hidden>
                      <span className="site-footer__legal-sep">|</span>
                    </li>
                  ) : null}
                  <li className="site-footer__legal-link-item">
                    <Link
                      href="#"
                      className="site-footer__legal-link type-body-base-regular"
                    >
                      {label}
                    </Link>
                  </li>
                </Fragment>
              ))}
            </ul>
          </nav>
        </div>
      </div>
    </footer>
  )
}
